import React, { useEffect, useState } from "react";
import {
  getOverview,
  getAllRiders,       // instead of getRiders
  getCaptains,        // instead of getApprovedCaptains
  getPendingCaptains,
  getAllRides,        // instead of getRides
  approveRider,       // instead of approveCaptain
  rejectRider,        // instead of rejectCaptain
  getSOSAlerts,
  resolveSOS
} from "../../services/api";

import { useAuth } from "../../contexts/AuthContext";
import {
  AppBar, Toolbar, Box, Typography, Button, CircularProgress,
  Table, TableHead, TableBody, TableRow, TableCell, Card,
  Grid, Paper, Tabs, Tab, Stack, Link
} from "@mui/material";

import GroupsIcon from "@mui/icons-material/Groups";
import VerifiedUserIcon from "@mui/icons-material/VerifiedUser";
import HourglassTopIcon from "@mui/icons-material/HourglassTop";
import CommuteIcon from "@mui/icons-material/Commute";
import PersonIcon from "@mui/icons-material/Person";

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [overview, setOverview] = useState({ users: 0, captains: 0, pendingCaptains: 0, rides: 0, riders: 0 });
  const [activeTab, setActiveTab] = useState("overview");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const fetchOverview = async () => {
    try {
      const res = await getOverview();
      setOverview(res.data.data);
    } catch {
      setError("Failed to load overview");
    }
  };

  const fetchData = async (type) => {
    setActiveTab(type);
    setLoading(true);
    setError("");
    try {
      let res;
      switch (type) {
        case "users": res = await getUsers(); break;
        case "captains": res = await getApprovedCaptains(); break;
        case "pending": res = await getPendingCaptains(); break;
        case "rides": res = await getRides(); break;
        case "riders": res = await getRiders(); break;
        case "sos": res = await getSOSAlerts(); break;   // 🚨 new
        default: res = { data: { data: [] } };
      }
      setData(res?.data?.data || []);
    } catch {
      setError("Failed to fetch data");
      setData([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchOverview(); }, []);

  const handleResolveSOS = async (id) => {
    await resolveSOS(id);
    fetchData("sos");
  };

  return (
    <Box sx={{ flexGrow: 1, bgcolor: "#f4f6f8", minHeight: "100vh" }}>
      <AppBar position="static" sx={{ bgcolor: "#34495e", mb: 4 }}>
        <Toolbar sx={{ display: "flex", justifyContent: "space-between" }}>
          <Typography variant="h6">Admin Dashboard</Typography>
          <Button variant="contained" color="error" onClick={logout}>Logout</Button>
        </Toolbar>
      </AppBar>

      <Box maxWidth="1300px" mx="auto" px={3} pb={5}>
        <Paper elevation={3} sx={{ borderRadius: 3, mb: 4 }}>
          <Tabs
            value={activeTab}
            onChange={(e, val) => {
              setData([]);
              if (val === "overview") fetchOverview();
              else fetchData(val);
              setActiveTab(val);
            }}
            variant="fullWidth"
          >
            <Tab label="Overview" value="overview" />
            <Tab label="Users" value="users" />
            <Tab label="Riders" value="riders" />
            <Tab label="Approved Captains" value="captains" />
            <Tab label="Pending Captains" value="pending" />
            <Tab label="Rides" value="rides" />
            <Tab label="SOS Alerts" value="sos" />  {/* 🚨 new tab */}
          </Tabs>
        </Paper>

        {/* 🚨 SOS Alerts table */}
        {activeTab === "sos" && !loading && (
          <Paper sx={{ p: 3, borderRadius: 3, boxShadow: 3 }}>
            <Typography variant="h6" mb={2} fontWeight="bold">SOS Alerts</Typography>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>User/Rider</TableCell>
                  <TableCell>Role</TableCell>
                  <TableCell>Time</TableCell>
                  <TableCell>Status</TableCell>
                  <TableCell>Actions</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {data.map((sos) => (
                  <TableRow key={sos._id}>
                    <TableCell>{sos.userId?.fullName || "-"}</TableCell>
                    <TableCell>{sos.role}</TableCell>
                    <TableCell>{new Date(sos.createdAt).toLocaleString()}</TableCell>
                    <TableCell>{sos.status}</TableCell>
                    <TableCell>
                      {sos.status === "active" && (
                        <Button
                          size="small"
                          color="success"
                          variant="outlined"
                          onClick={() => handleResolveSOS(sos._id)}
                        >
                          Resolve
                        </Button>
                      )}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </Paper>
        )}
      </Box>
    </Box>
  );
}
